// Check if today is a market holiday (NSE holidays 2026)
const now = new Date();
const istOffset = 5.5 * 60 * 60 * 1000;
const ist = new Date(now.getTime() + istOffset);
const dateStr = ist.toISOString().slice(0, 10); // YYYY-MM-DD

const holidays = [
  '2026-01-15', '2026-01-26', '2026-03-03', '2026-03-26',
  '2026-03-31', '2026-04-03', '2026-04-14', '2026-05-01',
  '2026-05-28', '2026-06-26', '2026-09-14', '2026-10-02',
  '2026-10-20', '2026-11-10', '2026-11-24', '2026-12-25'
];

if (holidays.includes(dateStr)) {
  return [];  // Skip — market holiday
}
return [{ json: { trading_day: true, date: dateStr } }];

// Check if MCX is open (9:00 - 23:30 IST, Mon-Fri)
const now = new Date();
const istHour = (now.getUTCHours() + 5) % 24 + (now.getUTCMinutes() + 30 >= 60 ? 1 : 0);
const istMin = (now.getUTCMinutes() + 30) % 60;
const mcxOpen = (istHour >= 9 && (istHour < 23 || (istHour === 23 && istMin <= 30)));
return [{ json: { mcx_open: mcxOpen, ist_hour: istHour, ist_min: istMin } }];

const data = $input.first().json;

// Handle holiday skip response
if (data.status === 'skipped') {
  return [{ json: { text: `⚠️ MWA Scan skipped: ${data.reason}` } }];
}

const alerts = [];
const diag = data.data_fetched || {};

// All fired scanners
const firedBull = data.fired_bull || [];
const firedBear = data.fired_bear || [];

const forexBull = firedBull.filter(s => s.startsWith('cds_'));
const forexBear = firedBear.filter(s => s.startsWith('cds_'));
const mcxBull = firedBull.filter(s => s.startsWith('mcx_'));
const mcxBear = firedBear.filter(s => s.startsWith('mcx_'));
const otherBull = firedBull.filter(s => !s.startsWith('cds_') && !s.startsWith('mcx_'));
const otherBear = firedBear.filter(s => !s.startsWith('cds_') && !s.startsWith('mcx_'));

if (forexBull.length > 0) {
  alerts.push(`\u{1F4B1} CDS BULL (${forexBull.length}): ${forexBull.join(', ')}`);
}
if (forexBear.length > 0) {
  alerts.push(`\u{1F4B1} CDS BEAR (${forexBear.length}): ${forexBear.join(', ')}`);
}
if (mcxBull.length > 0) {
  alerts.push(`\u{26CF} MCX BULL (${mcxBull.length}): ${mcxBull.join(', ')}`);
}
if (mcxBear.length > 0) {
  alerts.push(`\u{26CF} MCX BEAR (${mcxBear.length}): ${mcxBear.join(', ')}`);
}
if (otherBull.length > 0) {
  alerts.push(`\u{1F7E2} Equity BULL (${otherBull.length}): ${otherBull.slice(0,10).join(', ')}`);
}
if (otherBear.length > 0) {
  alerts.push(`\u{1F534} Equity BEAR (${otherBear.length}): ${otherBear.slice(0,10).join(', ')}`);
}

// Active chains
const chains = data.active_chains || [];
for (const c of chains) {
  alerts.push(`\u{1F517} Chain: ${c.name} (${c.complete ? 'COMPLETE' : 'partial'}) +${c.boost}%`);
}

// Promoted stocks
const promoted = data.promoted_stocks || [];
if (promoted.length > 0) {
  alerts.push(`\u{2B50} Promoted: ${promoted.slice(0,10).join(', ')}`);
}

// Build summary
const dir = data.direction || 'UNKNOWN';
const bullPct = (data.bull_pct || 0).toFixed(1);
const bearPct = (data.bear_pct || 0).toFixed(1);
const nse = diag.nse || 0;
const cds = diag.cds || 0;
const mcx = diag.mcx || 0;
const now = new Date();
const istTime = new Date(now.getTime() + 5.5*60*60*1000).toLocaleTimeString('en-IN', {hour:'2-digit', minute:'2-digit'});

let msg = `\u{1F4CA} MWA Extended Scan | ${istTime} IST\n`;
msg += `\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\n`;
msg += `Direction: ${dir} | Bull ${bullPct}% | Bear ${bearPct}%\n`;
msg += `Data: NSE=${nse} CDS=${cds} MCX=${mcx}\n`;
if (alerts.length > 0) {
  msg += `\n${alerts.join('\n')}`;
} else {
  msg += `\nNo signals fired this scan.`;
}

return [{ json: { text: msg } }];

// Check if CDS is open (9:00 - 17:00 IST, Mon-Fri)
const now = new Date();
const istHour = (now.getUTCHours() + 5) % 24 + (now.getUTCMinutes() + 30 >= 60 ? 1 : 0);
const cdsOpen = (istHour >= 9 && istHour < 17);
return [{ json: { cds_open: cdsOpen, ist_hour: istHour } }];
